/* ─── Copy to clipboard ─────────────────────────────────────── */
const copiedId        = ref(null)
const copiedPointerId = ref(null)

function makeSvg(icon, size = 24) {
  const vb = icon.vb || '0 0 24 24'
  const paths = Array.isArray(icon.d) ? icon.d : [icon.d]
  const pathEls = paths.map(d => `<path d="${d}"/>`).join('')
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" viewBox="${vb}" fill="currentColor">${pathEls}</svg>`
}

async function copyIcon(icon) {
  await navigator.clipboard.writeText(makeSvg(icon, 24))
  copiedId.value = icon.name
  setTimeout(() => { copiedId.value = null }, 1400)
}

function downloadIcon(icon) {
  const svg = makeSvg(icon, 24)
  const blob = new Blob([svg], { type: 'image/svg+xml' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = `${icon.name.replace(/\s+/g, '-')}.svg`
  a.click()
  URL.revokeObjectURL(url)
}

