function makePointerSvg(type, { pointer = 'no', activity = null, number = 12 } = {}) {
  // Two-circle structure matching Figma export:
  //   outer (r=13) = border token  →  type.outerFill
  //   inner (r=10.4, 80% of outer) = bcg token  →  type.innerFill
  const innerR = 10.4
  let content = ''
  if (pointer === 'yes-number')
    content = `<text x="16" y="20.5" text-anchor="middle" font-size="11" font-weight="700" fill="${type.fg}" font-family="Roboto,sans-serif">${number}</text>`
  else if (pointer === 'yes-symbol' && activity)
    content = activityContent(activity, type.fg)
  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32" width="32" height="32"><circle cx="16" cy="16" r="13" fill="${type.outerFill}"/><circle cx="16" cy="16" r="${innerR}" fill="${type.innerFill}"/>${content}</svg>`
}

async function copyPointer(key, svgStr) {
  await navigator.clipboard.writeText(svgStr)
  copiedPointerId.value = key
  setTimeout(() => { copiedPointerId.value = null }, 1400)
}

const totalCount = GROUPS.reduce((sum, g) => sum + g.icons.length, 0)
</script>

<template>
  <main class="ds-main">

    <!-- Title -->
    <section class="ds-section">
      <h1 class="ds-h1">Icons</h1>
      <p class="ds-lead">{{ totalCount }} icons · Material Design · 24 px (sm) · 16 px (xs)</p>
    </section>

    <!-- Sizing reference -->
    <section class="ds-section">
      <h2 class="ds-h2">Sizes</h2>
      <p class="ds-body">
        The system uses two icon sizes. Use 24 px alongside body text and in buttons;
        16 px in compact contexts like table cells, tags, and dense toolbars.
      </p>
      <div class="size-cards">
        <div v-for="{ label, token, px } in [{label:'sm',token:'24px',px:24},{label:'xs',token:'16px',px:16}]"
             :key="label" class="size-card">
          <div class="size-preview">
            <svg :width="px" :height="px" viewBox="0 0 24 24" fill="var(--grey-90)">
              <path d="M15.5 14h-.79l-.28-.27C15.41 12.59 16 11.11 16 9.5 16 5.91 13.09 3 9.5 3S3 5.91 3 9.5 5.91 16 9.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/>
            </svg>
          </div>
          <div class="size-meta">
            <span class="size-label-name">{{ label }}</span>
            <span class="size-label-px">{{ token }}</span>
          </div>
        </div>
      </div>
    </section>

    <!-- Icon groups -->
    <section v-for="group in GROUPS" :key="group.id" class="ds-section">
      <div class="group-header">
        <h2 class="ds-h2">{{ group.name }}</h2>
        <span class="group-count">{{ group.icons.length }}</span>
      </div>
      <p class="ds-body">{{ group.description }}</p>

      <div class="icon-grid">
        <div
          v-for="icon in group.icons"
          :key="icon.name"
          class="icon-card"
          :class="{ copied: copiedId === icon.name }"
          :title="`Click to copy SVG — ${icon.name}`"
          role="button" tabindex="0"
          @click="copyIcon(icon)"
          @keydown.enter.prevent="copyIcon(icon)"
          @keydown.space.prevent="copyIcon(icon)"
        >
          <button class="icon-dl-btn" :title="`Download ${icon.name}.svg`" @click.stop="downloadIcon(icon)">
            <svg width="10" height="10" viewBox="0 0 24 24" fill="currentColor"><path d="M19 9h-4V3H9v6H5l7 7 7-7zM5 18v2h14v-2H5z"/></svg>
          </button>
          <div class="icon-previews">
            <svg
              v-for="sz in (icon.sizes || [24, 16])"
              :key="sz"
              :width="sz" :height="sz"
              :viewBox="icon.vb || '0 0 24 24'"
              fill="currentColor" aria-hidden="true"
              :class="{ 'icon-sm': sz === 16, 'icon-xs': sz === 12 }"
            >
              <path v-for="(d, i) in (Array.isArray(icon.d) ? icon.d : [icon.d])" :key="i" :d="d"/>
            </svg>
          </div>
          <span class="icon-name">{{ icon.name }}</span>
          <span class="icon-copied-badge">Copied!</span>
        </div>
      </div>
    </section>

    <!-- Map Pointers -->
    <section class="ds-section">
      <div class="group-header">
        <h2 class="ds-h2">Map Pointers</h2>
        <span class="group-count">{{ MP_TYPES.length }} types</span>
      </div>
      <p class="ds-body">
        Circular markers placed on map views to represent vehicle positions — like Google Maps pins.
        Defined by <strong>type</strong> (color theme), <strong>size</strong> (sm → xl),
        <strong>state</strong> (main / hover / following), and
        <strong>pointer content</strong> (empty, number, or activity symbol).
      </p>

      <!-- 1. Types -->
      <div class="mp-subsection">
        <h3 class="mp-sub-h3">Types <span class="mp-sub-note">· md · main · no pointer</span></h3>
        <div class="mp-type-grid">
          <button
            v-for="type in MP_TYPES" :key="type.id"
            class="mp-type-card"
            :class="{ copied: copiedPointerId === type.id }"
            :title="`Click to copy — ${type.label}`"
            @click="copyPointer(type.id, makePointerSvg(type))"
          >
            <div class="mp-type-icon">
              <svg width="36" height="36" viewBox="0 0 32 32" fill="none" aria-hidden="true"
                style="filter:drop-shadow(0 2px 6px rgba(54,56,59,0.25))">
