                <circle cx="16" cy="16" r="10.4" :fill="type.innerFill"/>
              </svg>
            </div>
            <span class="mp-type-name">{{ type.label }}</span>
            <span class="icon-copied-badge">Copied!</span>
          </button>
        </div>
      </div>

