    <!-- Usage -->
    <section class="ds-section">
      <h2 class="ds-h2">Usage</h2>
      <p class="ds-body">
        Inline SVG with <code>currentColor</code> fill — icon inherits the text color of its container.
        Always include <code>aria-hidden="true"</code> for decorative icons and an accessible label for interactive ones.
      </p>
      <div class="usage-card">
        <p class="usage-label">Inline SVG (24 px)</p>
        <pre class="usage-code">&lt;svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"&gt;
  &lt;path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/&gt;
&lt;/svg&gt;</pre>
      </div>
      <div class="usage-card">
